async function apiFetch(path, options = {}) {
  const res = await fetch(path, {
    ...options,
    headers: {
      "Content-Type": "application/json",
      ...(options.headers || {}),
    },
  });
  const text = await res.text();
  if (!res.ok) {
    throw new Error(text || `Request failed: ${res.status}`);
  }
  try {
    return text ? JSON.parse(text) : null;
  } catch {
    return null;
  }
}

function FormModal({ state, onClose }) {
  const [values, setValues] = useState(state.initialValues || {});
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    setValues(state.initialValues || {});
    setError("");
    setSubmitting(false);
  }, [state]);

  const onChange = (name, nextValue) => {
    setValues((prev) => ({ ...prev, [name]: nextValue }));
  };

  const submit = async () => {
    try {
      setSubmitting(true);
      setError("");
      await state.onSubmit(values);
      onClose();
    } catch (e) {
      setError(e?.message || "Request failed");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div
      role="dialog"
      aria-modal="true"
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.45)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 9999,
      }}
      onMouseDown={(e) => {
        if (e.target === e.currentTarget) onClose();
      }}
    >
      <div
        style={{
          width: "min(680px, 92vw)",
          background: "#fff",
          borderRadius: 12,
          border: "1px solid #e5e7eb",
          boxShadow: "0 18px 60px rgba(0,0,0,0.25)",
          padding: 18,
        }}
      >
        <div style={{ display: "flex", justifyContent: "space-between", gap: 12 }}>
          <div>
            <div style={{ fontWeight: 800, fontSize: 16, color: "#111827" }}>
              {state.title}
            </div>
            {state.subtitle && (
              <div style={{ fontSize: 12, color: "#6b7280", marginTop: 4 }}>
                {state.subtitle}
              </div>
            )}
          </div>
          <button
            style={{
              background: "transparent",
              border: "none",
              cursor: "pointer",
              color: "#6b7280",
              fontSize: 18,
              lineHeight: 1,
              padding: 6,
            }}
            onClick={onClose}
            aria-label="Close"
          >
            ✕
          </button>
        </div>

        <div style={{ height: 10 }} />

        {error && (
          <div
            style={{
              background: "#fee2e2",
              color: "#b91c1c",
              border: "1px solid #fecaca",
              padding: "10px 12px",
              borderRadius: 8,
              marginBottom: 12,
              fontSize: 13,
            }}
          >
            {error}
          </div>
        )}

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: 12,
          }}
        >
          {state.fields.map((f) => (
            <div key={f.name} style={{ gridColumn: f.fullWidth ? "1 / -1" : "auto" }}>
              <div style={{ fontSize: 12, color: "#6b7280", marginBottom: 6 }}>
                {f.label}
              </div>
              {f.type === "select" ? (
                <select
                  value={values[f.name] ?? ""}
                  onChange={(e) => onChange(f.name, e.target.value)}
                  style={inputStyle}
                >
                  {(f.options || []).map((opt) => (
                    <option key={opt.value} value={opt.value}>
                      {opt.label}
                    </option>
                  ))}
                </select>
              ) : f.type === "textarea" ? (
                <textarea
                  value={values[f.name] ?? ""}
                  onChange={(e) => onChange(f.name, e.target.value)}
                  rows={3}
                  style={{
                    ...inputStyle,
                    resize: "vertical",
                  }}
                />
              ) : (
                <input
                  type={f.inputType || "text"}
                  placeholder={f.placeholder || ""}
                  value={values[f.name] ?? ""}
                  onChange={(e) => onChange(f.name, e.target.value)}
                  style={inputStyle}
                />
              )}
            </div>
          ))}
        </div>

        <div style={{ height: 14 }} />

        <div style={{ display: "flex", justifyContent: "flex-end", gap: 10 }}>
          <button
            style={{ ...btnOutline }}
            onClick={onClose}
            disabled={submitting}
          >
            Cancel
          </button>
          <button
            style={{ ...btnPrimary, background: state.primaryColor || "#3b82f6" }}
            onClick={submit}
            disabled={submitting}
          >
            {submitting ? "Saving..." : state.submitLabel || "Save"}
          </button>
        </div>
      </div>
    </div>
  );
}

