function ScheduleAssignment() {
  const times = [
    "7:00 AM",
    "9:00 AM",
    "11:00 AM",
    "1:00 PM",
    "3:00 PM",
    "5:00 PM",
  ];
  const days = ["MONDAY", "TUESDAY", "WEDNESDAY", "THURSDAY"];
  const defaultSlots = {
    "9:00 AM-TUESDAY": {
      code: "CS401",
      prof: "Prof. Gomez",
      room: "Room 301",
      color: SIDEBAR_BG,
    },
    "9:00 AM-MONDAY": {
      code: "MATH201",
      prof: "Prof. Abai",
      room: "Room 102",
      color: ACCENT,
    },
    "9:00 AM-WEDNESDAY": {
      code: "MATH301",
      prof: "Prof. Abai",
      room: "Room 102",
      color: ACCENT,
    },
    "11:00 AM-TUESDAY": {
      code: "BUS101",
      prof: "Prof. Supafly",
      room: "Room 401",
      color: "#f59e0b",
    },
    "11:00 AM-THURSDAY": {
      code: "BUS101",
      prof: "Prof. Supafly",
      room: "Room 401",
      color: "#f59e0b",
    },
    "1:00 PM-MONDAY": {
      code: "CS502",
      prof: "Prof. Gomez",
      room: "Room 302",
      color: SIDEBAR_BG,
    },
    "1:00 PM-WEDNESDAY": {
      code: "CS301",
      prof: "Prof. Gomez",
      room: "Room 301",
      color: SIDEBAR_BG,
    },
    "3:00 PM-TUESDAY": {
      code: "ENG401",
      prof: "Prof. Mulet",
      room: "Room 206",
      color: "#22c55e",
    },
    "3:00 PM-THURSDAY": {
      code: "ENG401",
      prof: "Prof. Mulet",
      room: "Room 206",
      color: "#22c55e",
    },
  };

  const [slots, setSlots] = useState(defaultSlots);

  useEffect(() => {
    const load = async () => {
      const d = await apiFetch("/api/schedules?term=Spring%202024");
      if (d?.slots && typeof d.slots === "object") setSlots(d.slots);
    };
    load().catch(() => {});
    const onRefresh = () => load().catch(() => {});
    window.addEventListener("schedules:refresh", onRefresh);
    return () => window.removeEventListener("schedules:refresh", onRefresh);
  }, []);

  useEffect(() => {
    const onPublish = async () => {
      const term = "Spring 2024";
      const payload = [];
      for (const t of times) {
        for (const d of days) {
          const slot = slots[`${t}-${d}`];
          if (!slot) continue;
          payload.push({
            time: t,
            day: d,
            code: slot.code,
            prof: slot.prof,
            room: slot.room,
            color: slot.color,
          });
        }
      }

      await apiFetch(`/api/schedules/${encodeURIComponent(term)}/publish`, {
        method: "POST",
        body: JSON.stringify({ slots: payload }),
      });
      window.dispatchEvent(new Event("schedules:refresh"));
    };

    window.addEventListener("schedule:publish", onPublish);
    return () => window.removeEventListener("schedule:publish", onPublish);
  }, [slots]);

  return (
    <div
      style={{
        background: "#fff",
        borderRadius: 8,
        border: "1px solid #e5e7eb",
        overflow: "hidden",
      }}
    >
      <div style={{ padding: "12px 18px", background: SIDEBAR_BG }}>
        <h3 style={{ fontWeight: 700, fontSize: 14, color: "#fff" }}>
          Weekly Schedule — Spring 2024
        </h3>
      </div>
      <div style={{ overflowX: "auto" }}>
        <table
          style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}
        >
          <thead>
            <tr style={{ background: "#f9fafb" }}>
              <th
                style={{
                  padding: "10px 14px",
                  textAlign: "left",
                  color: "#6b7280",
                  fontSize: 11,
                  fontWeight: 600,
                  width: 90,
                }}
              >
                TIME
              </th>
              {days.map((d) => (
                <th
                  key={d}
                  style={{
                    padding: "10px 14px",
                    textAlign: "left",
                    color: "#6b7280",
                    fontSize: 11,
                    fontWeight: 600,
                  }}
                >
                  {d}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {times.map((t) => (
              <tr key={t} style={{ borderTop: "1px solid #f3f4f6" }}>
                <td
                  style={{
                    padding: "8px 14px",
                    color: "#9ca3af",
                    fontSize: 12,
                    verticalAlign: "top",
                    paddingTop: 12,
                  }}
                >
                  {t}
                </td>
                {days.map((d) => {
                  const slot = slots[`${t}-${d}`];
                  return (
                    <td
                      key={d}
                      style={{ padding: 6, height: 72, verticalAlign: "top" }}
                    >
                      {slot && (
                        <div
                          style={{
                            background: slot.color,
                            color: "#fff",
                            borderRadius: 6,
                            padding: "8px 10px",
                            fontSize: 12,
                          }}
                        >
                          <div style={{ fontWeight: 700 }}>{slot.code}</div>
                          <div style={{ opacity: 0.85 }}>{slot.prof}</div>
                          <div style={{ opacity: 0.75 }}>{slot.room}</div>
                        </div>
                      )}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function AttendanceMonitoring() {
  const defaultStats = [
    {
      label: "Overall Attendance",
      value: "94.2%",
      icon: Icons.faculty,
      bg: "#dcfce7",
    },
    { label: "Late Arrivals", value: "12", icon: Icons.history, bg: "#fef9c3" },
    { label: "Absences", value: "8", icon: Icons.clearance, bg: "#fee2e2" },
    { label: "Exceptions", value: "5", icon: Icons.evaluation, bg: "#f3e8ff" },
  ];
  const [stats, setStats] = useState(defaultStats);

  const defaultRollup = [
    { label: "Present", count: 42, color: "#22c55e" },
    { label: "Late", count: 3, color: "#f59e0b" },
    { label: "Absent", count: 2, color: "#ef4444" },
    { label: "On Leave", count: 1, color: SIDEBAR_BG },
  ];
  const [rollup, setRollup] = useState(defaultRollup);

  const defaultPoints = [
    96, 95, 97, 94, 96, 93, 95, 94, 96, 95, 94, 96, 95, 94, 95,
  ];
  const [points, setPoints] = useState(defaultPoints);

  useEffect(() => {
    const load = async () => {
      const d = await apiFetch("/api/attendance/trend?term=Spring%202024");
      const t = d?.trend;
      if (!t) return;

      setStats((prev) =>
        prev.map((s) => {
          if (s.label === "Overall Attendance")
            return { ...s, value: t.overallAttendanceLabel };
          if (s.label === "Late Arrivals")
            return { ...s, value: t.lateArrivalsCountLabel };
          if (s.label === "Absences") return { ...s, value: t.absencesCountLabel };
          if (s.label === "Exceptions")
            return { ...s, value: t.exceptionsCountLabel };
          return s;
        }),
      );

      if (Array.isArray(t.rollup)) setRollup(t.rollup);
      if (Array.isArray(t.points)) setPoints(t.points);
    };

    load().catch(() => {});
  }, []);
  const W = 500,
    H = 120,
    minV = 90,
    maxV = 100;
  const toY = (v) => H - ((v - minV) / (maxV - minV)) * H;
  const toX = (i) => (i / (points.length - 1)) * W;
  const pathD = points
    .map((v, i) => `${i === 0 ? "M" : "L"}${toX(i)},${toY(v)}`)
    .join(" ");
  return (
    <div>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4,1fr)",
          gap: 14,
          marginBottom: 16,
        }}
      >
        {stats.map((s) => (
          <div
            key={s.label}
            style={{
              background: "#fff",
              border: "1px solid #e5e7eb",
              borderRadius: 8,
              padding: 18,
              display: "flex",
              gap: 14,
              alignItems: "center",
            }}
          >
            <div
              style={{
                background: s.bg,
                borderRadius: 8,
                padding: 10,
                color: "#6b7280",
              }}
            >
              {s.icon}
            </div>
            <div>
              <div style={{ fontSize: 26, fontWeight: 800, color: "#111827" }}>
                {s.value}
              </div>
              <div style={{ fontSize: 12, color: "#6b7280" }}>{s.label}</div>
            </div>
          </div>
        ))}
      </div>
      <div
        style={{ display: "grid", gridTemplateColumns: "1fr 260px", gap: 16 }}
      >
        <div
          style={{
            background: "#fff",
            borderRadius: 8,
            border: "1px solid #e5e7eb",
            padding: 20,
          }}
        >
          <h3
            style={{
              fontWeight: 700,
              fontSize: 15,
              color: "#111827",
              marginBottom: 16,
            }}
          >
            Attendance Trend (Last 30 Days)
          </h3>
          <svg viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: 120 }}>
            <path
              d={pathD}
              fill="none"
              stroke={SIDEBAR_BG}
              strokeWidth={2.5}
              strokeLinejoin="round"
            />
            {points.map((v, i) => (
              <circle key={i} cx={toX(i)} cy={toY(v)} r={3} fill={SIDEBAR_BG} />
            ))}
          </svg>
        </div>
        <div
          style={{
            background: "#fff",
            borderRadius: 8,
            border: "1px solid #e5e7eb",
            padding: 20,
          }}
        >
          <h3
            style={{
              fontWeight: 700,
              fontSize: 15,
              color: "#111827",
              marginBottom: 14,
            }}
          >
            Today's Rollup
          </h3>
          {rollup.map((r) => (
            <div
              key={r.label}
              style={{
                display: "flex",
                justifyContent: "space-between",
                padding: "10px 0",
                borderBottom: "1px solid #f3f4f6",
              }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <span
                  style={{
                    width: 8,
                    height: 8,
                    borderRadius: "50%",
                    background: r.color,
                    display: "inline-block",
                  }}
                />
                <span style={{ fontSize: 13, color: "#374151" }}>
                  {r.label}
                </span>
              </div>
              <span style={{ fontWeight: 700, color: r.color, fontSize: 13 }}>
                {r.count} faculty
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

